"use strict";import{gridCells as i}from"../helpers/grid.js";function S(n){return function(){let e=n+=1831565813;return e=Math.imul(e^e>>>15,e|1),e^=e+Math.imul(e^e>>>7,e|61),((e^e>>>14)>>>0)/4294967296}}function B(n,e,r){return r?r.some(u=>n>=u.x1&&n<=u.x2&&e>=u.y1&&e<=u.y2):!1}export function generateDefaultResources(n){const{seed:e=42,width:r,height:u,tileSize:t=16,density:a={Tree:.015,Bush:.007,Stone:.002},pathZones:y=[],border:m=32}=n,l=S(e+n.levelId.length),x=Math.floor(r/t),k=Math.floor(u/t),h=[];for(let o=0;o<k;o++)for(let s=0;s<x;s++){const f=s*t,d=o*t;if(B(s,o,y)||f<m||f>r-m-t||d<m||d>u-m-t)continue;const b=l();if(b<a.Tree){const c=p(l,3,4,.1);h.push({type:"tree",x:i(s),y:i(o),hp:c})}else if(b<a.Tree+a.Bush){const c=p(l,2,2,.1);h.push({type:"bush",x:i(s),y:i(o),hp:c})}else if(b<a.Tree+a.Bush+a.Stone){const c=p(l,3,4,.1);h.push({type:"stone",x:i(s),y:i(o),hp:c})}}return h}export function generateDeko(n){const{seed:e=42,width:r,height:u,tileSize:t=16,density:a={animBush:.002,animBushSmall:.002},pathZones:y=[],border:m=32}=n,l=S(e+n.levelId.length),x=Math.floor(r/t),k=Math.floor(u/t),h=[];for(let o=3;o<k;o++)for(let s=3;s<x;s++){const f=s*t,d=o*t;if(B(s,o,y)||f<m||f>r-m-t||d<m||d>u-m-t)continue;const b=l();if(b<a.animBushSmall)h.push({type:"animBushSmall",x:i(s),y:i(o)});else if(b<a.animBushSmall+a.animBush){const c=p(l,2,2,.1);h.push({type:"animBush",x:i(s),y:i(o)})}}return h}function p(n,e,r,u=.1){let t=Math.floor(n()*(r-e+1))+e;return n()<u&&(n()<.5?t=Math.max(1,t-1):t=t+1),t}export function getResourceFrame(n,e="outdoor"){let r=0;switch(n){case"bush":e==="desert"?r=2:r=0;break;case"tree":case"stone":e==="desert"?r=4:r=0;break;case"square":e==="desert"?r=1:r=0;break}return r}
